		"username": user.Username,
		"jti":      jti,
	})

	writeSuccess(c, http.StatusOK, gin.H{
		"access_token": token,
		"token_type":   "Bearer",
		"expires_at":   expiresAt.Format(time.RFC3339),
		"user":         user,
	})
}

