	}
	return s, nil
}

func countChunkFiles(tmpDir string) (int, error) {
	files, err := filepath.Glob(filepath.Join(tmpDir, "chunk_*.part"))
	if err != nil {
		return 0, err
	}
	return len(files), nil
}

