<script setup>
import { onMounted, reactive, ref } from 'vue'
import { message, Modal } from 'ant-design-vue'

import { api } from '../services/api'

const loading = ref(false)
const importLoading = ref(false)
const positions = ref([])
const candidates = ref([])
const searchResults = ref([])

const positionForm = reactive({
  title: '',
  description: '',
})

const candidateForm = reactive({
  id: null,
  full_name: '',
  phone: '',
  id_number: '',
  email: '',
  position_id: null,
  status: 'new',
})

const mergeForm = reactive({
  primary_candidate_id: '',
  duplicate_ids: '',
})

const searchQuery = ref('')

async function loadData() {
  loading.value = true
  try {
    const [pos, cands] = await Promise.all([api.listPositions(), api.listCandidates()])
    positions.value = pos
    candidates.value = cands
  } catch (err) {
    message.error(err.message || 'Failed to load recruitment data')
  } finally {
    loading.value = false
  }
}

async function createPosition() {
  if (!positionForm.title) {
    message.warning('Position title is required')
    return
  }
  try {
    await api.createPosition(positionForm)
    message.success('Position created')
    positionForm.title = ''
    positionForm.description = ''
    await loadData()
  } catch (err) {
    message.error(err.message || 'Failed to create position')
  }
}

function resetCandidateForm() {
  candidateForm.id = null
  candidateForm.full_name = ''
  candidateForm.phone = ''
  candidateForm.id_number = ''
  candidateForm.email = ''
  candidateForm.position_id = null
  candidateForm.status = 'new'
}

function editCandidate(row) {
  candidateForm.id = row.id
  candidateForm.full_name = row.full_name
  candidateForm.phone = ''
  candidateForm.id_number = ''
  candidateForm.email = row.email
  candidateForm.position_id = row.position_id
  candidateForm.status = row.status
  message.info('Enter updated phone and ID number to save candidate changes.')
}

async function submitCandidate() {
  if (!candidateForm.full_name || !candidateForm.phone || !candidateForm.id_number) {
    message.warning('Full name, phone and ID number are required')
    return
  }
  try {
    const payload = {
      full_name: candidateForm.full_name,
      phone: candidateForm.phone,
      id_number: candidateForm.id_number,
      email: candidateForm.email,
      position_id: candidateForm.position_id || null,
      status: candidateForm.status,
    }
    if (candidateForm.id) {
      await api.updateCandidate(candidateForm.id, payload)
      message.success('Candidate updated')
    } else {
      await api.createCandidate(payload)
      message.success('Candidate created')
    }
    resetCandidateForm()
    await loadData()
  } catch (err) {
    message.error(err.message || 'Failed to save candidate')
  }
}

async function importFile({ file }) {
  importLoading.value = true
  try {
    const result = await api.importCandidates(file)
    message.success(`Imported ${result.imported} candidates`)
    if (result.failed?.length) {
      message.warning(`${result.failed.length} rows failed during import`)
    }
    await loadData()
  } catch (err) {
    message.error(err.message || 'Import failed')
  } finally {
    importLoading.value = false
  }
}

async function runSearch() {
  if (!searchQuery.value) {
    searchResults.value = []
    return
  }
  try {
    searchResults.value = await api.searchCandidates(searchQuery.value)
  } catch (err) {
    message.error(err.message || 'Search failed')
  }
}

async function mergeDuplicates() {
  const primary = Number(mergeForm.primary_candidate_id)
  const duplicateIds = mergeForm.duplicate_ids
    .split(',')
    .map((item) => Number(item.trim()))
    .filter((num) => Number.isFinite(num) && num > 0)

  if (!primary || !duplicateIds.length) {
    message.warning('Primary ID and duplicate IDs are required')
    return
  }

  Modal.confirm({
    title: 'Merge duplicates',
    content: 'Duplicate records will be deleted after merge. Continue?',
    async onOk() {
      try {
        await api.mergeCandidates({
          primary_candidate_id: primary,
          duplicate_ids: duplicateIds,
        })
        message.success('Candidates merged')
        mergeForm.primary_candidate_id = ''
        mergeForm.duplicate_ids = ''
        await loadData()
      } catch (err) {
        message.error(err.message || 'Merge failed')
      }
    },
  })
}

onMounted(loadData)
</script>

<template>
  <a-spin :spinning="loading">
    <div class="grid-two">
      <a-card class="page-card" title="Create Position">
        <a-form layout="vertical">
          <a-form-item label="Title">
            <a-input v-model:value="positionForm.title" />
          </a-form-item>
          <a-form-item label="Description">
            <a-textarea v-model:value="positionForm.description" :rows="3" />
          </a-form-item>
          <a-button type="primary" @click="createPosition">Create Position</a-button>
        </a-form>
      </a-card>

      <a-card class="page-card" title="Bulk Resume Import (CSV/XLSX)">
        <a-upload :show-upload-list="false" :custom-request="importFile">
          <a-button type="primary" :loading="importLoading">Upload Import File</a-button>
        </a-upload>
        <p style="margin-top: 10px">Required columns: full_name, phone, id_number, email</p>
      </a-card>
    </div>

    <a-card class="page-card" title="Candidate Form" style="margin-top: 16px">
      <div class="grid-three">
        <a-input v-model:value="candidateForm.full_name" placeholder="Full name" />
        <a-input v-model:value="candidateForm.phone" placeholder="Phone" />
        <a-input v-model:value="candidateForm.id_number" placeholder="ID number" />
        <a-input v-model:value="candidateForm.email" placeholder="Email" />
        <a-select v-model:value="candidateForm.position_id" placeholder="Position" :allow-clear="true">
          <a-select-option v-for="position in positions" :key="position.id" :value="position.id">
            {{ position.title }}
          </a-select-option>
        </a-select>
        <a-select v-model:value="candidateForm.status">
          <a-select-option value="new">new</a-select-option>
          <a-select-option value="imported">imported</a-select-option>
          <a-select-option value="shortlisted">shortlisted</a-select-option>
          <a-select-option value="rejected">rejected</a-select-option>
        </a-select>
      </div>
      <div style="margin-top: 12px; display: flex; gap: 8px">
        <a-button type="primary" @click="submitCandidate">
          {{ candidateForm.id ? 'Update Candidate' : 'Create Candidate' }}
        </a-button>
        <a-button @click="resetCandidateForm">Reset</a-button>
      </div>
    </a-card>

    <a-card class="page-card" title="Merge Duplicates (by phone/ID)" style="margin-top: 16px">
      <div class="grid-three">
        <a-input v-model:value="mergeForm.primary_candidate_id" placeholder="Primary candidate ID" />
        <a-input v-model:value="mergeForm.duplicate_ids" placeholder="Duplicate IDs (comma-separated)" />
        <a-button type="primary" @click="mergeDuplicates">Merge</a-button>
      </div>
