		UploadTmpDir:  getEnv("UPLOAD_TMP_DIR", "storage/tmp"),
		MaxUploadMB:   getEnvInt64("MAX_UPLOAD_MB", 20),
	}

	if cfg.JWTExpHours <= 0 {
