		ORDER BY expiry_date ASC
	`, args...)
	if err != nil {
		writeError(c, http.StatusInternalServerError, "DB_ERROR", "failed to list qualifications")
		return
	}
	defer rows.Close()

	items := make([]gin.H, 0)
